// // This module implements a 3-bit binary down-counter with synchronous reset. It decrements on the rising edge of the clock signal 'clk' if the 'up_down' signal is high, and increments if the 'up_down' signal is low. The counter resets to 0 when the reset signal 'rst' is asserted high.
module up_down_counter(
    input clk,
    input rst,
    input up_down,
    output reg [2:0] count
);

    always @(posedge clk) begin
        if (rst)
            count <= 3'b000;
        else if (up_down)
            count <= count + 1;
        else
            count <= count - 1;
    end

endmodule
